/** Runtime config — single source of truth for which features are active.
 *
 * Rule of the house: if a feature is `true`, it must be available and must
 * work; if it's `false`, any code path that depends on it MUST refuse to run
 * (throw, not silently fall back). No half-states, no placeholders.
 *
 * Imported as `CONFIG` from anywhere in `nefan-core`, `nefan-html`, and the
 * bridge. `ai_server` / `narrative-mcp` read the JSON snapshot generated by
 * `scripts/dump-config.ts` from `data/runtime_config.json`.
 */

export interface NefanConfig {
  graphics: {
    /** Pre-rendered Mixamo sprite sheets on disk for the player. When false,
     *  the player is drawn as a coloured circle and no sheets are loaded. */
    player_sprites: boolean;
    /** img2img AI skin pass on top of the Mixamo sheet via ai_server's
     *  /skin_sprite_sheet endpoint. Requires player_sprites = true. */
    ai_skin: boolean;
    /** AI 2D sprites for entities via /generate_sprite (asset-cache). */
    ai_sprites: boolean;
    /** AI PBR textures for objects via /generate_texture. */
    ai_textures: boolean;
    /** AI GLB models for objects/buildings via /generate_model. */
    ai_models: boolean;
  };
  narrative: {
    /** Demand a live narrative listener (a second Claude Code session that
     *  called `narrative_listen`). If false, the only-LLM rule is relaxed —
     *  but there is no scripted fallback either, so the game just refuses to
     *  start. Default true. */
    require_llm: boolean;
    /** Reject LLM consequence aliases (show_dialogue→dialogue, text→delta).
     *  When true, the validator throws on aliases; when false it tolerates
     *  them. Default true. */
    strict_validator: boolean;
  };
  session: {
    /** Demand a live bridge (ws://localhost:9877 + http://localhost:9878).
     *  When true and the bridge is down, the game refuses to start. Default
     *  true. There is no `LocalGameClient` fallback any more. */
    require_bridge: boolean;
  };
  /** Knobs only meant for development. Production should leave these off. */
  dev: {
    /** Cache the bootstrap of a fresh session (world map + first scene) by
     *  gameId. When true and a cache entry exists for `start_session`'s
     *  gameId, the bridge replays it instead of asking the narrative engine,
     *  saving the ~90 s the LLM spends on the initial bootstrap. Cache lives
     *  in `nefan-core/data/initial_scene_cache/` (gitignored); delete the
     *  file (or the dir) to invalidate. */
    cache_initial_scene: boolean;
  };
  /** Python ai_server runtime. Lives here so there is exactly one config
   *  file in the repo; `scripts/dump-config.ts` emits the snapshot the
   *  server reads at startup. Fail-loud: a missing field is a hard error,
   *  not a `.get(key, default)` silent fallback. */
  ai_server: {
    llm_model: string;
    llm_timeout_s: number;
    port: number;
    cache_root: string;
    texture_cache_dir: string;
    model_cache_dir: string;
    skin_cache_dir: string;
    sprite_cache_dir: string;
    /** Cache for full-scene img2img backgrounds + outpainted extensions,
     *  served at /cache/scene/{hash}. */
    scene_cache_dir: string;
    /** Cache for occluder sprites cut out of the scene image (SAM via fal.ai),
     *  served at /cache/segment/{hash}. */
    segment_cache_dir: string;
    texture_resolution: number;
    texture_steps: number;
    /** Meshy image-to-image model for scene generation (best top-down:
     *  nano-banana-pro). Also valid: nano-banana, nano-banana-2, gpt-image-2. */
    scene_model: string;
    /** Path (relative to repo root) of the art-style reference image passed as
     *  the 2nd reference to Meshy so generated scenes match a target game look. */
    scene_style_image: string;
    /** fal.ai SAM model id used to segment occluder sprites out of the scene
     *  image (box-prompt mode). Needs FAL_KEY in the environment. */
    segment_model: string;
    /** fal.ai SAM3 model id for open-vocabulary discovery of props the image
     *  model invented (Phase 3, text-prompted multi-instance). Needs FAL_KEY. */
    discover_model: string;
    texture_lazy_load: boolean;
    /** Mount the /diagnostic/* router (skin_test_* endpoints used for manual
     *  parameter sweeps with curl). Off in production: the routes 404. */
    expose_diagnostic: boolean;
  };
}

export const CONFIG: NefanConfig = {
  graphics: {
    player_sprites: false,
    ai_skin: false,
    ai_sprites: false,
    ai_textures: false,
    ai_models: false,
  },
  narrative: {
    require_llm: true,
    strict_validator: true,
  },
  session: {
    require_bridge: true,
  },
  dev: {
    cache_initial_scene: false,
  },
  ai_server: {
    llm_model: "claude-sonnet-4-5-20250514",
    llm_timeout_s: 300,
    port: 8765,
    cache_root: "cache",
    texture_cache_dir: "cache/textures",
    model_cache_dir: "cache/models",
    skin_cache_dir: "cache/skins",
    sprite_cache_dir: "cache/sprites",
    scene_cache_dir: "cache/scenes",
    segment_cache_dir: "cache/segments",
    texture_resolution: 512,
    texture_steps: 4,
    scene_model: "nano-banana-pro",
    scene_style_image: "skinning_lab/bases/battlemap-town-style.png",
    segment_model: "fal-ai/sam2/image",
    discover_model: "fal-ai/sam-3/image",
    texture_lazy_load: true,
    expose_diagnostic: false,
  },
};
